  ('aboriginal-6f0ba476-moex-00661', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '雅美族原住民依其傳統文化申請回復傳統名字者，受有多少申請次數之限制？', '["1次", "2次", "3次", "無次數限制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00662', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '有關原住民族土地或部落範圍土地劃設小組之組成規定，下列敘述何者錯誤？', '["劃設小組係由部落自主組成", "劃設人員具有原住民身分者，不得少於總數二分之一", "劃設小組由鄉（鎮、市、區）公所協助部落組成", "原住民族委員會得委託機關團體協助辦理劃設作業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00663', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依現行法之規定，原住民族傳統領域土地之劃設成果，應提請何一組織討論與議決？', '["部落會議", "原住民保留地土地權利審查委員會", "直轄市、縣（市）議會", "鄉（鎮、市）民代表會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00664', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '位於花蓮縣吉安鄉的全牛料理餐廳，經營者甲為阿美族馬太鞍部落族人，明知「馬蘭阿美飲酒歡樂歌」 （專用權人為大馬蘭地區部落）、「阿美族馬太鞍部落男性傳統服飾：五片流蘇裙」（專用權人為阿美族 馬太鞍部落）係具傳統智慧創作專用權之權利標的，為招攬生意，在其餐廳使用前述已取得智慧創作 專用權之權利內容，請問下列那項利用行為，構成智慧創作專用權之侵害？', '["甲穿著「五片流蘇裙」提供服務", "甲使用「五片流蘇裙」之圖案設計T恤販售", "甲於營業時間公開演唱「馬蘭阿美飲酒歡樂歌」", "甲於營業時間聘請大馬蘭地區部落族人演唱「馬蘭阿美飲酒歡樂歌」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00665', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依原住民族教育法之規定，教育部及原住民族委員會應鼓勵原住民學生達多少人數之公立大專校院， 設置原住民族學生資源中心？', '["20人", "30人", "50人", "100人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00666', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '下列有關公有土地增劃編原住民保留地審查作業之辦理機關，何者錯誤？', '["原住民族委員會為主辦機關", "財政部國有財產署為協辦機關", "直轄市或縣政府為協辦機關", "鄉（鎮、市、區）公所為執行機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00667', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '有關原住民族綜合發展基金之敘述，下列何者錯誤？', '["原住民族綜合發展基金由政府設立，辦理原住民族經濟發展業務、輔導事業機構、住宅之興辦、租 售、建購及修繕業務", "基金之法定來源包括原住民族地區溫泉取用費提撥款", "基金之法定用途包括原住民族就學基金支出", "原住民族綜合發展基金管理會召集人，為原住民族委員會副主任委員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00668', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依據原住民族傳統智慧創作保護條例，經認定為智慧創作者，依法取得智慧創作專用權之敘述，何者 錯誤？', '["智慧創作經認定屬於申請人者，應准予登記，並自登記之日起，由申請人取得智慧創作專用權", "智慧創作經認定屬於申請人及其他特定原住民族或部落者，自登記之日起，由申請人及其他特定原 住民族或部落共同取得智慧創作專用權", "智慧創作不能認定屬於特定原住民族或部落者，應登記為公共所有，並自登記之日起，由全民取得 智慧創作專用權", "智慧創作專用權人之名稱有變更者，應申請變更登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00669', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依據原住民族工作權保障法處理原住民勞資爭議時，下列敘述何者正確？', '["原住民勞資爭議，應依據勞資爭議處理法規定辦理", "勞資權利事項與調整事項之爭議，勞方當事人有二分之一以上為原住民時，關於調解委員或仲裁委 員有特別規定", "原住民在工作職場發生就業歧視或勞資糾紛，各級主管機關應予以法律諮詢、提供律師及全額訴訟 費之扶助", "直轄市、縣（市）政府依據勞資爭議處理法第30條規定推薦核備之仲裁委員名單中，應至少1人 至3人為具有原住民身分者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
